const crypto = require('crypto');
const items = $input.first().json.response?.body?.items?.item ?? [];
const results = [];
for (const item of (Array.isArray(items) ? items : [items])) {
  const attachmentUrl = item.ntceSpecDocUrl ?? '';
  const modifiedAt = item.rgstDt ?? '';
  const provisionalHash = crypto.createHash('sha256').update(attachmentUrl + modifiedAt).digest('hex');
  results.push({ json: { source: 'g2b', externalId: item.bidNtceNo, title: item.bidNtceNm, category: item.ntceInsttNm, region: item.dminsttNm, url: item.ntceSpecDocUrl, publishedAt: item.rgstDt, deadlineAt: item.bidClseDt, attachmentUrl, provisionalHash } });
}
return results;
